import React from "react";
import { useDrop } from "react-dnd";
import { recordDrop } from "./tracker";

function DropBox({ acceptName, label, isMatched, onDrop }) {
  const [{ isOver }, drop] = useDrop(() => ({
    accept: "ITEM",
    drop: (item) => {
      if (item.name === acceptName) {
        recordDrop(true);
        if (onDrop) onDrop();
      } else {
        recordDrop(false);
      }
    },
    collect: (monitor) => ({
      isOver: monitor.isOver(),
    }),
  }));

  const backgroundColor = isMatched ? "#90EE90" : isOver ? "#90EE90" : "#ADD8E6";
  const borderColor = isMatched ? "#00AA00" : "#333";
  const borderWidth = isMatched ? "4px" : "2px";

  return (
    <div
      ref={drop}
      style={{
        width: "120px",
        height: "120px",
        margin: "20px",
        backgroundColor: backgroundColor,
        border: `${borderWidth} solid ${borderColor}`,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        fontSize: "20px",
        borderRadius: "10px",
        transition: "all 0.2s ease",
        boxShadow: isMatched || isOver ? "0 0 10px rgba(0,170,0,0.5)" : "none",
        fontWeight: isMatched ? "bold" : "normal",
      }}
    >
      {label}
    </div>
  );
}

export default DropBox;
